#include <iostream>
#include <vector>
using namespace std;
class Solution
{
public:
void heapify(vector<int>& nums)
{
int n = nums.size();
_heapify(nums, n-1);
}
void _heapify(vector<int>& nums, int n)
{
int largest = n;
int left = 2*n + 1;
int right = 2*n + 2;

if (left < n && nums[left]>nums[largest])
 largest = left;

if (right < n && nums[right]>nums[largest])
 largest = right;

if (largest != n)
{
swap(nums[n], nums[largest]);
_heapify(nums, largest);
}
}
};

int main() {
Solution s;

int n;
scanf("%d",&n);

int nums[n];
for (int i = 0;i < n;i++) {
 scanf("%d",&nums[i]);
}
s.heapify(nums);

for (int i = 0;i < n;i++) {
 printf("%d ",nums[i]);
}
return 0;
}
